var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마술사 지망생이라고?","JPN":"マジシャンの卵なの？","ENG":"So you're an aspiring magician?","TWN":"你是魔術師志願生？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응!","JPN":"そうよ！","ENG":"Yup!","TWN":"嗯！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미에 다니는 학생이라고 해서 모두 침식체와 싸우고 싶어하는 건 아니니까.","JPN":"アカデミーに通う生徒だからって、みんなが侵食体と戦いたいわけじゃないからね。","ENG":"Not everybody at the Academy wants to fight C.O.s for a living.","TWN":"就算是學院的學生，也不是所有人都想和侵蝕體戰鬥的。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"난 말이지, 싸움이 아닌 방법으로도 카운터가 세상에 도움이 될 수 있다는 보여 주고 싶어.","JPN":"私はね、戦闘じゃないやり方でもカウンターがこの世の役に立てるってことを見せたいの。","ENG":"I want to show people that Counters can be helpful in ways other than fighting.","TWN":"我就是想證明，就算不進行戰鬥，制裁者也可以用別的方法對世界作出貢獻。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아직은 서툴지만 언젠가 대마술사가 되면 전세계를 돌면서 사람들을 위해 무료로 공연을 해 줄 거야.","JPN":"まだまだだけど、いつか凄腕のマジシャンになったら、世界中を周って人々のために無料でショーを披露したいんだ。","ENG":"I may be clumsy now, but one day I'll travel the world and put on shows for free when I'm a great magician.","TWN":"雖然現在還差很多，但總有一天我會成為大魔術師。我會在世界各地巡迴演出，進行免費表演。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"지금도 매달 학생회 주최로 교내 공연을 하고 있어.","JPN":"今も毎月、生徒会主催で校内ショーをやってるの。","ENG":"I've been putting on monthly magic shows on campus, hosted by the Student Council.","TWN":"現在我每個月都在學生會主辦的校內演出中表演。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"별이 점지한 대마술사 미카★스타 라고 하면 아카데미에서는 꽤 유명하다고.","JPN":"お星様に導かれしマジシャン、ミカ★スターはこのアカデミーではかなり有名だよ。","ENG":"Ask anyone in the Academy about the great magician Mika★Star, the Comet Wonder! They'll know!","TWN":"在學院裡大家說的《星星的指引大魔術師-米卡★斯塔》就是指我，也算是小有名氣。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그거 대단하네.","JPN":"……それはすごいね。","ENG":"That's... impressive.","TWN":"……你真厲害。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너라면 꼭 해낼 수 있을 거야.","JPN":"あなたならきっとできると思う。","ENG":"I'm sure you'll make it big one day.","TWN":"我相信，你一定可以成功。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"고마워! 미나는 좋은 사람이구나!","JPN":"ありがと！　ミナちゃんはいい人なんだね！","ENG":"Thank you! You're so sweet!","TWN":"謝謝！米娜你是個好人！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"다음 공연 때 새로운 마술을 공개할 생각인데 혹시 조수로 도와 줄 수 있을까?","JPN":"次のショーの時、新しい手品を披露する予定なんだけど、アシスタントとして手伝ってくれない？","ENG":"I plan on showcasing a new trick during my next show. Could you maybe help me as an assistant?","TWN":"我想在下次演出時公開新魔術，你願意當我的助手嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"조수?","JPN":"アシスタント？","ENG":"Assistant?","TWN":"助手？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응. <color=#ffd34c>연필이 사라지는 마술</color>이라는 건데 공연을 하려면 조수가 한 명 필요하거든.","JPN":"そう。<color=#ffd34c>鉛筆が消えるマジック</color>というものなんだけど、ショーにはアシスタントが一人必要なの。","ENG":"Yeah. It's a <color=#ffd34c>magic trick that makes a pencil disappear</color>, but I'll need an assistant for it.","TWN":"嗯。要進行<color=#ffd34c>鉛筆消失的魔術</color>表演，那時需要一名助手。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"쪼오금 위험하긴 하지만...... 그래도 정말 재미있을 거야!","JPN":"ちょーっとだけ危険なところもあるけど……絶対楽しいからね！","ENG":"Although it can be a teeny bit dangerous... It should still be so much fun!","TWN":"雖然有一點點危險……但我保證很有趣！"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......연필이 어디로 사라지는데?","JPN":"……鉛筆はどこに消えるの？","ENG":"W-where does this pencil disappear to?","TWN":"……鉛筆消失之後去哪裡？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"모, 몸 속으로?","JPN":"か、体の中に？","ENG":"I-In your body?","TWN":"身、身體裡？"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미안. 사양할게.","JPN":"ごめん、遠慮しておくね。","ENG":"Sorry. I'll pass.","TWN":"對不起，我拒絕。"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"히잉......","JPN":"ふえん……","ENG":"Aw...","TWN":"哭哭……"},"stage":{"bg":"CLASS","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 도착했다. 여기야.","JPN":"あ、着いたよ。ここね。","ENG":"Ah, we're here. This is it.","TWN":"啊，到了。就是這裡。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"모의전투실? 뭐 하는 곳인데?","JPN":"模擬戦闘室？　何をする場所なの？","ENG":"Combat Simulation Center? What is this place?","TWN":"模擬戰鬥室？這是什麼地方？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아카데미 수업은 일반 교과랑 전투 교과로 나눠져 있거든.","JPN":"アカデミー授業は一般教科と戦闘教科に分かれているんだよ。","ENG":"The courses here are categorized into general classes and combat classes.","TWN":"學院的學習分為普通課程和戰鬥課程。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"일반 교과는 다른 평범한 고등학교들이랑 비슷해.","JPN":"一般教科は普通の高校と似たような内容だね。","ENG":"General classes are just like any other high school classes.","TWN":"普通課程跟普通高中生學的差不多。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 아카데미 학생들은 모두 카운터니까, 혹시 모를 사태에 대비해서 최소한의 전투 훈련을 받는 게 규칙이야.","JPN":"でも、アカデミーの生徒はみんなカウンターだから、万が一の場合に備えて最低限の戦闘訓練を受けるのが校則なの。","ENG":"But since all the students here are Counters, they're required to receive combat training, just in case.","TWN":"但學院的學生因為都是制裁者，所以為了應對未知的事態，需要進行一定的戰鬥訓練。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래......?","JPN":"そう……？","ENG":"Is that right?","TWN":"……是嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응. 원래는 관리국이 협조해 줘서 적당한 재난지역에 가는 식이었는데......","JPN":"うん。元々は管理局の協力の下に、災害地域に行く仕組みになっていたけど……","ENG":"Yup. They used to have the Administration escort us into a suitable disaster zone...","TWN":"嗯。原本管理局會提供協助，被派到適當的災難地區進行戰鬥的……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"실전은 역시 위험하잖아?","JPN":"実戦はやっぱり危険でしょ？","ENG":"But real combat is too dangerous, right?","TWN":"但實戰畢竟有危險嘛？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래서 모의전투실이 만들어진 뒤로는 대부분 여기서 전투 훈련을 하고 있어.","JPN":"だから模擬戦闘室が作られてからは、ほとんどここで戦闘訓練を受けているの。","ENG":"So most students have been training at the Combat Simulation Center ever since it was built.","TWN":"所以，自從有了模擬戰鬥室之後，大部分學生都在這裡進行戰鬥訓練。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"여기 있는 전투 시뮬레이터는 거의 실제와 같은 가상 환경을 만들어 주거든.","JPN":"ここにある戦闘シミュレーターはほぼ現実と同じ仮想環境を再現できるよ。","ENG":"The combat simulator here creates a virtual environment that's almost exactly like reality.","TWN":"這裡的戰鬥模擬器可以營造出幾乎與現實一樣的虛擬環境。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나 넌 편입생이니까, 먼저 이 시뮬레이터로 전투 능력을 측정할 거야.","JPN":"ミナちゃんは編入生だから、まずはこのシミュレーターで戦闘能力を測定するね。","ENG":"Since you're a transfer student, they'll gauge your combat ability with this simulator first.","TWN":"米娜你是新生，所以需要先用模擬器測試下戰鬥能力。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"튜토리얼 스테이지는 별로 안 어려우니까 너무 걱정하지 않아도 돼.","JPN":"チュートリアルステージはあまり難しくないから、あまり心配しなくていいよ。","ENG":"Don't worry. The tutorial's not very hard.","TWN":"新手教學關卡很簡單，你不用太擔心。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그럼 얼른 타! 바로 시작할게!","JPN":"さあ、乗ってみて！　今すぐ始めるね。","ENG":"Well, get in there! It'll get started right away!","TWN":"那快坐上去吧！馬上開始！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};